.mens-opt-enhanced-pdp {

	> *:not(.linkbar, .navbar, .site-footer) > .container {
		max-width: 1440px;
		margin: 0 auto;
	}
	.extended-center-border-above,
	.extended-center-border-below {
		@media #{layout.$medium-screen-and-smaller} {
			&::before,
			&::after {
				display: none !important;
			}
		}
	}

	/*
	* =============================
	* Hero
	* =============================
	*/
	.boost-your-testosterone.hero {
		background-color: colors.$color-white;
		padding: fonts.rem(40px) fonts.rem(64px);
		@media #{layout.$medium-screen-and-smaller} {
			padding: fonts.rem(16px) fonts.rem(32px) fonts.rem(40px);
			flex-direction: column;
			gap: fonts.rem(24px);
		}
		@media #{layout.$small-screen-only} {
			padding-inline: fonts.rem(16px);
		}

		.container.grid {
			gap: fonts.rem(64px);
			grid-template-columns: 600px 1fr;
			@media #{layout.$medium-screen-and-smaller} {
				grid-template-columns: 1fr;
				gap: fonts.rem(24px);
			}
		}

		.container {
			@media #{layout.$medium-screen-and-smaller} {
				display: flex;
				flex-direction: column;
				gap: fonts.rem(24px);
			}
		}

		// Left column — image
		.media-wrapper {
			padding: 0;
			display: flex;
			align-items: center;
			background-color: colors.$color-white;
			@media #{layout.$medium-screen-and-smaller} {
				order: 1;
			}

			.media-block {
				width: 600px;
				aspect-ratio: 1 / 1;
				@media #{layout.$medium-screen-and-smaller} {
					width: 100%;
					max-width: fonts.rem(600px);
					height: auto;
					margin-left: auto;
					margin-right: auto;
				}

				video {
					width: 100%;
					height: 100%;
					object-fit: cover;
				}
			}
		}

		// Right column — content
		.content-wrapper {
			padding: 0;
			display: flex;
			flex-direction: column;
			justify-content: center;
			gap: fonts.rem(40px);
			@media #{layout.$medium-screen-and-smaller} {
				order: 2;
				gap: fonts.rem(24px);
			}

			// Title
			.title-block h2 {
				font-family: fonts.$STIX-Two-Text;
				font-weight: 400;
				font-size: fonts.rem(54px);
				line-height: 1;
				letter-spacing: -1.08px;
				color: colors.$color-black;
				max-width: 576px;
				@media #{layout.$medium-screen-and-smaller} {
					font-size: fonts.rem(36px);
					letter-spacing: -0.72px;
					max-width: none;
				}
			}

			// List items
			.content-block {
				ul {
					list-style: none;
					margin: 0;
					padding: 0;
					display: flex;
					flex-direction: column;
					gap: fonts.rem(16px);
					@media #{layout.$medium-screen-and-smaller} {
						gap: fonts.rem(12px);
					}
				}

				li {
					border-left: 2px solid rgba(96, 91, 82, 0.2);
					padding-left: fonts.rem(12px);
					font-family: fonts.$DM-Sans;
					font-weight: 500;
					font-size: fonts.rem(22px);
					line-height: 1.1;
					letter-spacing: -0.44px;
					color: colors.$color-black;
					@media #{layout.$medium-screen-and-smaller} {
						font-size: fonts.rem(18px);
						letter-spacing: -0.36px;
						padding-left: fonts.rem(8px);
					}
				}
			}

			// CTA block
			.cta-block {
				display: flex;
				flex-direction: column;
				gap: fonts.rem(8px);
				width: 100%;

				.cta-wrapper {
					width: 100%;
				}

				a {
					width: 100%;
					height: 48px;
					border-radius: 2px;
					padding: 0 fonts.rem(48px);
					box-sizing: border-box;
				}
			}

			// Badges — pull up to 8px below CTA (40px gap - 32px = 8px)
			.badges-wrapper {
				margin-top: fonts.rem(-32px);
				display: flex;
				flex-wrap: wrap;
				align-items: center;
				justify-content: center;
				gap: fonts.rem(10px);
				// Adjust for 24px gap (24px - 16px = 8px)
				@media #{layout.$medium-screen-and-smaller} {
					margin-top: fonts.rem(-16px);
				}

				.badge {
					display: flex;
					align-items: center;
					height: 20px;

					img {
						width: auto;
						height: 24px;
					}

					span {
						font-family: fonts.$DM-Sans;
						font-weight: 400;
						font-size: fonts.rem(14px);
						line-height: 1.4;
						letter-spacing: -0.28px;
						color: colors.$color-gray;
						text-align: center;
					}
				}
			}
		}
	}

	/*
	* =============================
	* Marquee / Trustpilot Ratings
	* =============================
	*/
	.marquee.trustpilot-ratings {
		background-color: colors.$color-white;

		.container {
			display: flex;
			align-items: center;
			gap: fonts.rem(16px);
			padding: fonts.rem(16px);
			@media #{layout.$medium-screen-and-smaller} {
				flex-direction: column;
				padding: fonts.rem(16px) 0;
			}
		}

		.trustpilot-wrapper {
			flex-shrink: 0;
			@media only screen and (max-width: 445px) {
				min-width: unset;
			}
		}

		.trustpilot-static {
			display: flex;
			align-items: center;
			gap: fonts.rem(8px);
			text-decoration: none;
			color: #191919;
			white-space: nowrap;

			.tp-text {
				font-weight: 700;
				font-size: fonts.rem(12px);
			}

			.tp-stars {
				height: 14px;
			}

			.tp-count {
				font-size: fonts.rem(12px);
			}

			.tp-brandmark {
				width: auto;
				height: 16px;
			}

			@media only screen and (max-width: 445px) {
				flex-wrap: wrap;
				justify-content: center;
				gap: fonts.rem(4px) fonts.rem(8px);
			}
		}

		.reviews-wrapper {
			flex: 1 0 0;
			overflow: hidden;
			position: relative;
			@media #{layout.$medium-screen-and-smaller} {
				flex: 0 0 auto;
				width: 100%;
			}

			// Fade edges
			&::before,
			&::after {
				content: '';
				position: absolute;
				top: 0;
				bottom: 0;
				width: 78px;
				z-index: 1;
				pointer-events: none;
			}

			&::before {
				left: 0;
				background: linear-gradient(to right, colors.$color-white, transparent);
			}

			&::after {
