				padding: 0;
				gap: fonts.rem(40px);
				padding: 0;
				background-color: transparent;
			}
		}

		// Title
		.title-block {
			text-align: center;

			.title {
				font-family: fonts.$STIX-Two-Text;
				font-weight: 400;
				font-size: fonts.rem(54px);
				line-height: 1;
				letter-spacing: -1.08px;
