	/*
	* =============================
	* Testosterone Injections
	* =============================
	*/
	.injections-section {
		background-color: colors.$color-white;
		align-items: flex-start;
		padding: fonts.rem(64px);
		@media #{layout.$medium-screen-and-smaller} {
			padding: fonts.rem(40px) 0;
		}

		// Left — gallery in .container
		.container {
			display: grid;
			grid-template-columns: 1fr 1fr;
			gap: fonts.rem(64px);
			@media #{layout.$medium-screen-and-smaller} {
				grid-template-columns: 1fr;
				gap: fonts.rem(24px);
			}
		}

		// Left — image gallery grid (desktop) + slider (tablet/mobile)
		.gallery-wrapper {
			display: flex;
			justify-content: center;
			align-items: center;
			@media #{layout.$medium-screen-and-smaller} {
				display: block;
				overflow: hidden;
				min-width: 0;
			}

			.gallery-carousel.grid {
				display: grid;
				grid-template-columns: repeat(2, 1fr);
				grid-template-rows: repeat(3, 1fr);
				gap: fonts.rem(8px);
				@media #{layout.$medium-screen-and-smaller} {
					display: none;
				}
			}

			.gallery-image {
				width: 100%;
				max-height: fonts.rem(462px);
				aspect-ratio: 1 / 1;
				object-fit: cover;
				display: block;
			}

			// Slider + thumbnail nav (tablet/mobile only)
			.injections-slider-wrapper {
				display: none;
				@media #{layout.$medium-screen-and-smaller} {
					display: block;
					overflow: hidden;
					min-width: 0;
				}

				.injections-main-carousel {
					position: relative;
					display: flex;
					overflow-x: auto;
					scroll-snap-type: x mandatory;
					-webkit-overflow-scrolling: touch;
					scrollbar-width: none;
					gap: fonts.rem(8px);
					margin-bottom: fonts.rem(12px);
					cursor: grab;
					@media #{layout.$medium-screen-and-smaller} {
						padding-left: fonts.rem(32px);
						scroll-padding-left: fonts.rem(32px);
					}
					@media #{layout.$small-screen-only} {
						padding-left: fonts.rem(16px);
						scroll-padding-left: fonts.rem(16px);
					}

					&::-webkit-scrollbar {
						display: none;
					}

					&::after {
						content: '';
						flex-shrink: 0;
						width: max(#{fonts.rem(64px)}, calc(100vw - #{fonts.rem(462px)}));
						order: 9999;
					}

					.slide {
						scroll-snap-align: start;
						flex-shrink: 0;
						width: calc(100% - #{fonts.rem(32px)});
						max-width: fonts.rem(462px);
						@media #{layout.$small-screen-only} {
							width: calc(100% - #{fonts.rem(16px)});
						}

						&[data-slide="0"] {
							order: 1;
						}
						&[data-slide="1"] {
							order: 2;
						}
						&[data-slide="2"] {
							order: 4;
						}
						&[data-slide="3"] {
							order: 3;
						}
						&[data-slide="4"] {
							order: 5;
						}
						&[data-slide="5"] {
							order: 6;
						}
					}
				}

				.injections-thumbs {
					display: flex;
					gap: fonts.rem(8px);
					@media #{layout.$medium-screen-and-smaller} {
						padding: 0 fonts.rem(32px);
					}
					@media #{layout.$small-screen-only} {
						padding: 0 fonts.rem(16px);
					}

					.thumb {
						flex: 1 1 0;
						min-width: 0;
						max-width: fonts.rem(54px);
						cursor: pointer;

						img {
							width: 100%;
							aspect-ratio: 1 / 1;
							object-fit: cover;
							display: block;
							border-radius: fonts.rem(4px);
							border: 2px solid transparent;
							opacity: 0.5;
							transition: opacity 0.2s ease, border-color 0.2s ease;
						}

						&.active img {
							opacity: 1;
							border-color: colors.$color-black;
						}
						&[data-slide="0"] {
							order: 1;
						}
						&[data-slide="1"] {
							order: 2;
						}
						&[data-slide="2"] {
							order: 4;
						}
						&[data-slide="3"] {
							order: 3;
						}
						&[data-slide="4"] {
							order: 5;
						}
						&[data-slide="5"] {
							order: 6;
						}
					}
				}
			}
		}

		// Right — content + FAQ
		.content-wrapper {
			flex: 1 0 0;
			display: flex;
			flex-direction: column;
			gap: 0;
			@media #{layout.$medium-screen-and-smaller} {
				flex: 0 0 auto;
				width: 100%;
			}
		}

		// Content block (title, list, CTA, badges)
		.content-block {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(24px);
			@media #{layout.$medium-screen-and-smaller} {
				padding-inline: fonts.rem(32px);
			}
			@media #{layout.$small-screen-only} {
				padding-inline: fonts.rem(16px);
			}

			.title-block {
				display: flex;
				flex-direction: column;
				gap: fonts.rem(16px);

				.title {
					font-family: fonts.$STIX-Two-Text;
					font-weight: 400;
					font-size: fonts.rem(54px);
					line-height: 1;
					letter-spacing: -1.08px;
					color: colors.$color-black;
					@media #{layout.$medium-screen-and-smaller} {
						font-size: fonts.rem(36px);
						letter-spacing: -0.72px;
					}
				}

				.subtitle {
					font-family: fonts.$DM-Sans;
					font-weight: 400;
					font-size: fonts.rem(22px);
					line-height: 1.4;
					letter-spacing: -0.16px;
					color: colors.$color-black;
					@media #{layout.$medium-screen-and-smaller} {
						font-weight: 500;
						font-size: fonts.rem(18px);
						letter-spacing: -0.36px;
					}
				}
			}

			// List items with left border
			.list-block {
				ul {
					list-style: none;
					margin: 0;
					padding: 0;
					display: flex;
					flex-direction: column;
					gap: fonts.rem(16px);
					@media #{layout.$medium-screen-and-smaller} {
						gap: fonts.rem(12px);
					}
				}

				li {
					border-left: 2px solid rgba(96, 91, 82, 0.2);
					padding-left: fonts.rem(12px);
					font-family: fonts.$DM-Sans;
					font-weight: 500;
					font-size: fonts.rem(22px);
					line-height: 1.1;
					letter-spacing: -0.44px;
					color: colors.$color-black;
					@media #{layout.$medium-screen-and-smaller} {
						font-size: fonts.rem(18px);
						letter-spacing: -0.36px;
						padding-left: fonts.rem(8px);
					}
				}
			}

			// CTA + badges
			.cta-block {
				display: flex;
				flex-direction: column;
				gap: fonts.rem(8px);

				.injections-cta-block {
					width: 100%;

					.cta-wrapper {
						width: 100%;
					}

					a {
						width: 100%;
						height: 48px;
						border-radius: 2px;
						padding: 0 fonts.rem(48px);
						box-sizing: border-box;
					}
				}

				.badges-wrapper {
					display: flex;
					flex-wrap: wrap;
					align-items: center;
					justify-content: center;
					gap: fonts.rem(10px);

					.badge {
						display: flex;
						align-items: center;
						height: 20px;

						img {
							width: auto;
							height: 24px;
						}

						span {
							font-family: fonts.$DM-Sans;
							font-weight: 400;
							font-size: fonts.rem(14px);
							line-height: 1.4;
							letter-spacing: -0.28px;
							color: colors.$color-gray;
							text-align: center;
						}
					}
				}
			}
		}

		// FAQ accordion
		.faq-block {
			margin-top: fonts.rem(32px);
			@media #{layout.$medium-screen-and-smaller} {
				padding-inline: fonts.rem(32px);
			}
			@media #{layout.$small-screen-only} {
				padding-inline: fonts.rem(16px);
			}

			.faq-item {
				border-bottom: 1px solid rgba(96, 91, 82, 0.1);

				&:first-child {
					border-top: 1px solid rgba(96, 91, 82, 0.1);
				}
			}

			.faq-header {
				display: flex;
				align-items: center;
				justify-content: space-between;
				padding: fonts.rem(20px) 0;
				cursor: pointer;
				gap: fonts.rem(16px);
				@media #{layout.$medium-screen-and-smaller} {
					padding: fonts.rem(12px) fonts.rem(12px) fonts.rem(12px) 0;
				}

				.faq-question {
					font-family: fonts.$DM-Sans;
					font-weight: 500;
					font-size: fonts.rem(18px);
					line-height: 1.1;
					letter-spacing: -0.36px;
					color: colors.$color-black;
				}

			.faq-icon {
				display: flex;
				align-items: center;
				justify-content: center;
				width: 24px;
				height: 24px;
				flex-shrink: 0;
				position: relative;

				.icon-line {
					position: absolute;
					background-color: colors.$color-black;
					transition: transform 0.3s ease;
				}

				.line-horizontal {
					width: 24px;
					height: 1px;
				}

				.line-vertical {
					width: 1px;
					height: 24px;
				}
			}
			}

			.faq-content {
				max-height: 0;
				overflow: hidden;
				transition: max-height 0.4s ease;

				.faq-item-answer {
					padding: 0 0 fonts.rem(20px);
					font-family: fonts.$DM-Sans;
					font-weight: 400;
					font-size: fonts.rem(14px);
					line-height: 1.4;
					letter-spacing: -0.14px;
					color: colors.$color-black;
				}
			}

		// Open state
		.faq-item.open {
			.faq-icon {
				.line-horizontal {
					transform: rotate(45deg);
				}

				.line-vertical {
					transform: rotate(45deg);
				}
			}

				.faq-content {
					max-height: 500px;
				}
			}
		}
	}

	/*
	* =============================
	* Testimonials
	* =============================
	*/
	.testimonials {
		&::after {
			left: 50%;
		}
		.container {
			position: relative;
			padding: 4rem;
			@media #{layout.$medium-screen-and-smaller} {
				padding: 2.5rem 0;
			}
			@media #{layout.$small-screen-only} {
				padding: 2.5rem 0;
			}
			.wrapper {
				padding: 0;
			}
			.title-wrapper {
				max-width: 1000px;
				margin-inline: auto;
				text-align: center;
				margin-bottom: 2rem;
				padding-inline: 0;
				@media #{layout.$medium-screen-and-smaller} {
					padding-inline: 2.5rem;
				}
				@media #{layout.$small-screen-only} {
					padding-inline: 1rem;
				}
				h2 {
					color: #000;
					font-family: "STIX Two Text", serif;
					font-size: 3.625rem;
					font-weight: 400;
					line-height: 1;
					letter-spacing: -1.16px;
					margin-bottom: 1rem;
					@media #{layout.$medium-screen-and-smaller} {
						font-size: 2.25rem;
						letter-spacing: -0.72px;
					}
				}
				p {
					color: #000;
					font-family: "DM Sans", sans-serif;
					font-size: 1.375rem;
					font-weight: 500;
					line-height: 1;
					letter-spacing: -0.44px;
					@media #{layout.$medium-screen-and-smaller} {
						font-size: 1.125rem;
						letter-spacing: -0.36px;
					}
				}
				.stars-wrapper {
					display: flex;
					flex-direction: row;
					align-items: center;
					justify-content: center;
					gap: fonts.rem(8px);
					margin-bottom: fonts.rem(16px);
					@media only screen and (max-width: 315px) {
						flex-direction: column;
					}
					img {
						width: fonts.rem(86px);
						height: fonts.rem(15px);
						position: relative;
						bottom: fonts.rem(1px);
					}
					span {
						color: colors.$color-black;
						font-family: fonts.$DM-Sans;
						font-size: fonts.rem(16px);
						font-weight: 400;
						line-height: 140%;
						letter-spacing: -0.16px;
					}
				}
			}
			.carousel-wrapper {		
				overflow-x: hidden;
				overflow-y: visible;
				width: 100%;
				max-width: 100vw;
				.slick-track {
					margin: auto;
					display: flex !important;
					align-items: stretch;
				}
				.testimonial-item {
					padding: 2rem;
					border-radius: 20px;
					background: #F1F0EF;
					flex-direction: column;
					gap: 1rem;
					margin-inline: 0.75rem;
					@media #{layout.$small-screen-only} {
						margin-inline: 0.25rem;
					}
					&-rating img {
						height: 15px;
						width: auto;
					}

					&-title span {
						color: #000;
						font-family: "DM Sans", sans-serif;
						font-size: 1.125rem;
						font-weight: 500;
						line-height: 1;
						letter-spacing: -0.36px;
						@media #{layout.$small-screen-only} {
							font-size: 1rem;
							font-weight: 700;
							letter-spacing: -0.32px;
						}
					}

					&-description {
						flex: 1;
						span {
							color: #000;
							font-family: "DM Sans", sans-serif;
							font-size: 1rem;
							font-weight: 400;
							line-height: 1.4;
							letter-spacing: -0.16px;
							@media #{layout.$small-screen-only} {
								font-size: 0.875rem;
								letter-spacing: -0.14px;
							}
						}
					}

					&-attribution {
						color: #000;
						font-family: "DM Sans", sans-serif;
						font-size: 1rem;
						font-weight: 400;
						line-height: 1.4;
						letter-spacing: -0.16px;
						span.name {
							font-weight: 700;
							line-height: 1;
							letter-spacing: -0.32px;
						}
					}
				}
			}

			.slick-initialized .testimonial-item {
				display: flex !important;
			}
		}

	}

	/*
	* =============================
	* Alternatives
	* =============================
	*/
	.alternatives {
		padding: fonts.rem(32px) fonts.rem(64px);
		position: relative;

		.container {
			position: relative;
			z-index: 1;
			background-color: colors.$color-white;
			display: flex;
			flex-direction: column;
			align-items: center;
			gap: fonts.rem(40px);
			padding: fonts.rem(32px) 0;
		}

		// Title block
		.title-wrapper {
			text-align: center;

			.title-block {
				display: flex;
				flex-direction: column;
				gap: fonts.rem(16px);
				align-items: center;
			}

			.title {
				font-family: fonts.$STIX-Two-Text;
				font-weight: 400;
				font-size: fonts.rem(54px);
				line-height: 1;
				letter-spacing: -1.08px;
				color: colors.$color-black;
			}

			.subtitle {
				font-family: fonts.$DM-Sans;
				font-weight: 500;
				font-size: fonts.rem(22px);
				line-height: 1;
				letter-spacing: -0.44px;
				color: colors.$color-black;
			}

			.description {
				font-family: fonts.$DM-Sans;
				font-weight: 400;
				font-size: fonts.rem(16px);
				line-height: 1.4;
				letter-spacing: -0.16px;
				color: colors.$color-black;
			}
		}

		// Product cards — row with CTA below
		.grid-block {
			display: flex;
			flex-wrap: wrap;
			justify-content: center;
			gap: fonts.rem(32px);
			width: 100%;
		}

		.grid-item {
			display: flex;
			flex-direction: column;
			align-items: center;
			gap: fonts.rem(24px);

			.image-wrapper {
				width: 360px;
				height: 360px;
				border-radius: 21px;
				overflow: hidden;
				background-color: colors.$color-gray-light;

				img {
					width: 100%;
					height: 100%;
					object-fit: cover;
				}
			}

			.item-content {
				display: flex;
				flex-direction: column;
				gap: fonts.rem(8px);
				align-items: center;
				text-align: center;

				.item-title {
					font-family: fonts.$DM-Sans;
					font-weight: 400;
					font-size: fonts.rem(28px);
					line-height: 1.1;
					letter-spacing: -0.56px;
					color: colors.$color-black;
				}

				.item-description {
					font-family: fonts.$DM-Sans;
					font-weight: 400;
					font-size: fonts.rem(16px);
					line-height: 1.4;
					letter-spacing: -0.16px;
					color: colors.$color-black;
				}
			}
		}

		// CTA — force onto its own row, button centered at 366px
		.alternatives-cta-block {
			flex-basis: 100%;
			display: flex;
			justify-content: center;
			@media #{layout.$small-screen-only} {
				flex-basis: unset;
				width: 100%;
			}

			.cta-wrapper {
				width: 366px;
			}

			a {
				width: 100%;
				height: 48px;
				border-radius: 2px;
				padding: 0 fonts.rem(48px);
				box-sizing: border-box;
				@media #{layout.$small-screen-only} {
					padding: 0;
				}
			}
		}

		// ------ Tablet ------
		@media #{layout.$medium-screen-and-smaller} {
			padding: 40px 32px;

			&::before {
				display: none;
			}

			.container {
				gap: 24px;
				padding: 0;
				background-color: transparent;
			}

			.title-wrapper {
				.title-block {
					gap: 8px;
				}

				.title {
					font-size: 36px;
					letter-spacing: -0.72px;
				}

				.subtitle {
					font-size: 18px;
					letter-spacing: -0.36px;
				}
			}

			// Cards become horizontal (image left, text right)
			.grid-block {
				gap: 32px;
			}

			.grid-item {
				flex-direction: row;
				align-items: center;
				flex: 1 0 0;
				gap: 24px;

				.image-wrapper {
					width: 104px;
					height: 104px;
					border-radius: 10px;
					flex-shrink: 0;
				}

				.item-content {
					align-items: flex-start;
					text-align: left;

					.item-title {
						font-weight: 500;
						font-size: 22px;
						letter-spacing: -0.44px;
					}
				}
			}
		}
	}
}

@keyframes marquee-scroll {
	from {
		transform: translateX(0);
	}
	to {
		transform: translateX(var(--marquee-offset, -50%));
	}
}
